func refineKind(kind string, node *sitter.Node, src []byte) string {
	if kind != "class" {
		return kind
	}
	content := strings.TrimSpace(node.Content(src))
	switch {
	case strings.HasPrefix(content, "struct "):
		return "struct"
	case strings.HasPrefix(content, "enum "):
