package sem

import (
	"context"
	"sort"
	"strings"

	treesitter "github.com/tree-sitter/go-tree-sitter"

	"github.com/suhaanthayyil/entire-sem/internal/sem/pgsql"
)

func parsePostgresSQL(content string) ([]Entity, ParseStatus) {
	src := []byte(content)
	parser := treesitter.NewParser()
	defer parser.Close()
	if err := parser.SetLanguage(pgsql.GetLanguage()); err != nil {
		return nil, ParseStatus{ParseError: true, Detail: err.Error()}
	}
	tree := parser.ParseCtx(context.Background(), src, nil)
	if tree == nil {
		return nil, ParseStatus{ParseError: true, Detail: "tree-sitter parse failed"}
	}
	defer tree.Close()

	root := tree.RootNode()
	var entities []Entity
	walkSQLEntities(root, src, &entities)
	sort.Slice(entities, func(i, j int) bool {
		if entities[i].StartLine == entities[j].StartLine {
			return entities[i].Name < entities[j].Name
		}
		return entities[i].StartLine < entities[j].StartLine
	})
	if root.HasError() {
		return entities, ParseStatus{ParseError: true, Detail: "tree-sitter syntax error nodes present"}
	}
	return entities, ParseStatus{}
}

func walkSQLEntities(node *treesitter.Node, src []byte, entities *[]Entity) {
	if !validSQLNode(node) {
		return
	}
	entity, ok := sqlEntityFromNode(node, src)
	if ok {
		*entities = append(*entities, entity)
	}
	for i := uint(0); i < node.NamedChildCount(); i++ {
		walkSQLEntities(node.NamedChild(i), src, entities)
	}
}

func sqlEntityFromNode(node *treesitter.Node, src []byte) (Entity, bool) {
	var kind string
	var name string
	switch node.Kind() {
	case "create_table":
		kind = "table"
		name = sqlTSObjectName(node, src)
	case "create_function":
		kind = "function"
		name = sqlTSObjectName(node, src)
	case "create_view", "create_materialized_view":
		kind = "view"
		name = sqlTSObjectName(node, src)
	case "create_index":
		kind = "index"
		name = sqlTSIndexName(node, src)
	case "create_trigger":
		kind = "trigger"
		name = sqlTSObjectName(node, src)
	case "statement":
		var ok bool
		kind, name, ok = sqlStatementEntityText(sqlTSContent(node, src))
		if !ok {
			return Entity{}, false
		}
	default:
		return Entity{}, false
	}
	if name == "" {
		return Entity{}, false
	}

	block := sqlTSContent(node, src)
	signature := sqlTSSignature(node, src)
	entity := Entity{
		Kind:        kind,
		Name:        name,
		Signature:   signature,
		StartLine:   int(node.StartPosition().Row) + 1,
		EndLine:     int(node.EndPosition().Row) + 1,
		BodyHash:    hash(normalize(block)),
		Fingerprint: hash(normalize(entityFingerprintSource(Entity{Name: name, Signature: signature}, block))),
	}
	return entity, true
}

func sqlTSObjectName(node *treesitter.Node, src []byte) string {
	for i := uint(0); i < node.NamedChildCount(); i++ {
		child := node.NamedChild(i)
		if validSQLNode(child) && child.Kind() == "object_reference" {
			if name := sqlTSReferenceName(child, src); name != "" {
				return name
			}
		}
	}
	return ""
}

func sqlTSIndexName(node *treesitter.Node, src []byte) string {
	for i := uint(0); i < node.NamedChildCount(); i++ {
		child := node.NamedChild(i)
		if !validSQLNode(child) {
			continue
		}
		switch child.Kind() {
		case "object_reference":
			continue
		case "identifier", "literal":
			if name := sqlTSIdentifierContent(child, src); name != "" {
				return name
			}
		}
	}
	return ""
}

func sqlTSReferenceName(node *treesitter.Node, src []byte) string {
	var parts []string
	for i := uint(0); i < node.NamedChildCount(); i++ {
		child := node.NamedChild(i)
		if !validSQLNode(child) {
			continue
		}
		switch child.Kind() {
		case "identifier", "literal":
			if part := sqlTSIdentifierContent(child, src); part != "" {
				parts = append(parts, part)
			}
		}
	}
	return strings.Join(parts, ".")
}

func sqlStatementEntityText(content string) (string, string, bool) {
	content = strings.TrimSpace(content)
	lower := strings.ToLower(content)
	if !strings.HasPrefix(lower, "create ") {
		return "", "", false
	}
	if name := matchSQLCreatePolicyName(content); name != "" {
		return "policy", name, true
	}
	return "", "", false
}

func sqlTSSignature(node *treesitter.Node, src []byte) string {
	start := node.StartByte()
	end := node.EndByte()
	if body := sqlTSFirstBodyLikeChild(node); validSQLNode(body) {
		end = body.StartByte()
	}
	if end <= start || int(end) > len(src) {
		end = node.EndByte()
	}
	signature := strings.TrimSpace(string(src[start:end]))
	if index := strings.IndexByte(signature, '\n'); index >= 0 {
		signature = signature[:index]
	}
	return strings.TrimSpace(strings.TrimRight(signature, "{:; \t\r\n"))
}

func sqlTSFirstBodyLikeChild(node *treesitter.Node) *treesitter.Node {
	for i := uint(0); i < node.NamedChildCount(); i++ {
		child := node.NamedChild(i)
		if validSQLNode(child) && child.Kind() == "function_body" {
			return child
		}
	}
	return nil
}

func sqlTSIdentifierContent(node *treesitter.Node, src []byte) string {
	content := strings.TrimSpace(sqlTSContent(node, src))
	return strings.Trim(content, "`\"")
}

func sqlTSContent(node *treesitter.Node, src []byte) string {
	if !validSQLNode(node) {
		return ""
	}
	start := node.StartByte()
	end := node.EndByte()
	if end < start || int(end) > len(src) {
		return ""
	}
	return string(src[start:end])
}

func validSQLNode(node *treesitter.Node) bool {
	return node != nil
}

