package sem

import (
	"context"
	"fmt"
	"testing"

	sitter "github.com/smacker/go-tree-sitter"
	"github.com/suhaanthayyil/entire-sem/internal/sem/pgsql"
)

func TestDebugSQLTree(t *testing.T) {
	input := `create extension if not exists vector;

create table public.contracts (
  id uuid primary key,
  embedding vector(1536),
  created_at timestamptz not null default now(),
  status text generated always as ('active') stored,
  check (status in ('active', 'archived'))
);

create or replace function public.touch_contract()
returns trigger
language plpgsql
as $$
begin
  new.created_at := now();
  return new;
end;
$$;

create trigger contracts_touch
before update on public.contracts
for each row execute function public.touch_contract();

create index contracts_embedding_idx on public.contracts using ivfflat (embedding vector_cosine_ops);

create policy "contracts are readable"
on public.contracts for select
using (true);

insert into public.contracts (id)
values ('00000000-0000-0000-0000-000000000000')
on conflict (id) do update set created_at = excluded.created_at;
`
	src := []byte(maskPostgresUnsupportedSyntax(input))
	fmt.Println(string(src))
	root, err := sitter.ParseCtx(context.Background(), src, pgsql.GetLanguage())
	if err != nil {
		t.Fatal(err, pgsql.Version())
	}
	fmt.Println(root.String())
	fmt.Println(root.HasError())
}

