-- Phase 5 audit fix: the RSS import RPC was writing the GUID into source_links
-- when the RSS <item> had no <link>. PodcastIndex feeds frequently emit only
-- a GUID (often a UUID), so episode_dictionary rows ended up with
-- source_links = {84c17130-be7b-11f0-a56a-03025de97f84} and that string was
-- then returned by list_shared_catalog_episodes/get_episode_detail as
-- sourceUrl — showing as a broken external link.
--
-- The new logic only accepts http(s) URLs into source_links and falls back to
-- the feed homepage when the item has none. The GUID continues to live in
-- external_ids.rssGuid and in the dedupe_key.
--
-- Also retro-cleans existing rows where the first source_link is not a URL.

create or replace function public.import_podcast_feed_items(
  p_feed_source_id uuid,
  p_items jsonb,
  p_feed_meta jsonb default null,
  p_finished boolean default true
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_feed public.podcast_feed_sources%rowtype;
  v_homepage_url text;
  v_item jsonb;
  v_seen integer := 0;
  v_inserted integer := 0;
  v_published_at timestamptz;
  v_duration integer;
  v_guid text;
  v_link text;
  v_audio_url text;
  v_source_url text;
  v_source_link text;
  v_episode_id uuid;
begin
  select * into v_feed
  from public.podcast_feed_sources
  where id = p_feed_source_id
  for update;
  if v_feed.id is null then
    raise exception 'Feed source not found';
  end if;

  select homepage_url into v_homepage_url
  from public.podcast_dictionary
  where id = v_feed.podcast_id;

  update public.podcast_dictionary
  set
    title = coalesce(nullif(p_feed_meta->>'title', ''), title),
    publisher = coalesce(nullif(p_feed_meta->>'publisher', ''), publisher),
    artwork_url = coalesce(nullif(p_feed_meta->>'artworkUrl', ''), artwork_url),
    homepage_url = coalesce(nullif(p_feed_meta->>'homepageUrl', ''), homepage_url),
    rss_feed_url = coalesce(rss_feed_url, v_feed.feed_url)
  where id = v_feed.podcast_id;

  for v_item in select * from jsonb_array_elements(coalesce(p_items, '[]'::jsonb))
  loop
    v_seen := v_seen + 1;
    v_guid := nullif(v_item->>'guid', '');
    v_link := nullif(v_item->>'link', '');
    v_audio_url := nullif(v_item->>'audioUrl', '');
    v_published_at := nullif(v_item->>'publishedAt', '')::timestamptz;
    v_duration := nullif(v_item->>'durationSeconds', '')::integer;

    -- Dedupe key still prefers the stable GUID.
    v_source_url := coalesce(v_link, v_guid, v_feed.feed_url);

    -- source_links only accepts http(s) values; otherwise fall back to the
    -- podcast homepage (or omit if none) so the UI never renders a broken
    -- non-URL string as a clickable source.
    v_source_link := case
      when v_link ~ '^https?://' then v_link
      when v_homepage_url ~ '^https?://' then v_homepage_url
      else null
    end;

