func TestDebugSQLFailures(t *testing.T) {
	rootDir := "/Users/thomi/Projects/podcasts"
	var out strings.Builder
	parser := sitter.NewParser()
	parser.SetLanguage(pgsql.GetLanguage())
	count := 0
	_ = filepath.WalkDir(rootDir, func(path string, d os.DirEntry, err error) error {
		if err != nil || d.IsDir() || !strings.HasSuffix(path, ".sql") {
			return nil
		}
		content, err := os.ReadFile(path)
		if err != nil {
			return nil
		}
		masked := []byte(maskPostgresUnsupportedSyntax(string(content)))
		tree, err := parser.ParseCtx(context.Background(), nil, masked)
		if err != nil || tree == nil || !tree.RootNode().HasError() {
			return nil
		}
		rel, _ := filepath.Rel(rootDir, path)
		out.WriteString("FILE " + rel + "\n")
		writeSQLErrors(&out, tree.RootNode(), masked, 0, 8)
		count++
		if count >= 20 {
			return filepath.SkipAll
		}
		return nil
	})
	if err := os.WriteFile("/private/tmp/sql-debug.txt", []byte(out.String()), 0o644); err != nil {
		t.Fatal(err)
	}
	t.Fatalf("wrote %d failing files", count)
}

func writeSQLErrors(out *strings.Builder, node *sitter.Node, src []byte, depth, limit int) int {
	if node == nil || node.IsNull() || limit <= 0 {
		return 0
	}
	written := 0
	if node.IsError() || node.IsMissing() {
		start := int(node.StartByte())
		end := int(node.EndByte())
		contextStart := max(0, start-120)
		contextEnd := min(len(src), end+160)
		snippet := strings.Join(strings.Fields(string(src[contextStart:contextEnd])), " ")
		out.WriteString(fmt.Sprintf("  %s %d:%d %q\n", node.Type(), node.StartPoint().Row+1, node.StartPoint().Column+1, snippet))
		written++
	}
	if !node.HasError() {
		return written
	}
	for i := 0; i < int(node.NamedChildCount()) && written < limit; i++ {
		written += writeSQLErrors(out, node.NamedChild(i), src, depth+1, limit-written)
	}
	return written
}

