	out := make([]ExternalRecord, 0, len(ids))
	for _, id := range ids {
		out = append(out, seen[id])
	}
	return out
}

func externalParts(id string) (string, string) {
	rest := strings.TrimPrefix(id, "external:")
	kind, value, ok := strings.Cut(rest, ":")
	if !ok {
		return "unknown", rest
	}
