func yamlDirectChildIndent(parent yamlBlock, lines []string) int {
	parentIndent := yamlIndent(lines[parent.StartLine-1])
	childIndent := -1
	for index := parent.StartLine; index < parent.EndLine && index < len(lines); index++ {
		line := lines[index]
		if yamlIgnoreLine(line) {
			continue
