// Thin wrapper around the OpenAI embeddings endpoint. We avoid a hard
// dependency on the openai SDK so the bundle stays small and tests can
// pass a custom fetch implementation.

const OPENAI_EMBEDDINGS_URL = "https://api.openai.com/v1/embeddings";
const EMBEDDING_BATCH_SIZE = 64;
const MAX_RETRIES = 5;

export type EmbeddingsConfig = {
  apiKey: string;
  model: string;
};

export type EmbedTextsOptions = {
  config: EmbeddingsConfig;
  fetchImpl?: typeof fetch;
  signal?: AbortSignal;
};

type OpenAIEmbeddingResponse = {
  data?: Array<{ index: number; embedding: number[] }>;
  error?: { message?: string };
};

function jitter(ms: number) {
  return ms + Math.floor(Math.random() * ms);
}

async function sleep(ms: number, signal?: AbortSignal) {
  return new Promise<void>((resolve, reject) => {
    if (signal?.aborted) {
      reject(new Error("Embedding aborted"));
      return;
    }
    const timer = setTimeout(resolve, ms);
    signal?.addEventListener("abort", () => {
      clearTimeout(timer);
      reject(new Error("Embedding aborted"));
    }, { once: true });
  });
}

async function embedBatch({
  inputs,
  config,
  fetchImpl,
  signal,
}: {
  inputs: string[];
  config: EmbeddingsConfig;
  fetchImpl: typeof fetch;
  signal?: AbortSignal;
}): Promise<number[][]> {
  let attempt = 0;
  let lastError: Error | null = null;

  while (attempt < MAX_RETRIES) {
    attempt += 1;
    try {
      const response = await fetchImpl(OPENAI_EMBEDDINGS_URL, {
        method: "POST",
        signal,
        headers: {
          "content-type": "application/json",
          authorization: `Bearer ${config.apiKey}`,
        },
        body: JSON.stringify({
          model: config.model,
          input: inputs,
        }),
      });

      if (response.status === 429 || response.status >= 500) {
        const retryAfter = Number(response.headers.get("retry-after"));
        const backoff = Number.isFinite(retryAfter) && retryAfter > 0
          ? retryAfter * 1_000
          : jitter(500 * 2 ** (attempt - 1));
        await sleep(backoff, signal);
        lastError = new Error(`OpenAI embeddings ${response.status}`);
        continue;
      }

      const payload = (await response.json()) as OpenAIEmbeddingResponse;
      if (!response.ok) {
        const message = payload.error?.message ?? `OpenAI embeddings request failed with ${response.status}`;
        throw new Error(message);
      }
      const data = payload.data ?? [];
      const sorted = [...data].sort((a, b) => a.index - b.index);
      if (sorted.length !== inputs.length) {
        throw new Error(`Expected ${inputs.length} embeddings, got ${sorted.length}`);
      }
      return sorted.map((row) => row.embedding);
    } catch (error) {
      lastError = error instanceof Error ? error : new Error(String(error));
      if (attempt >= MAX_RETRIES) break;
      await sleep(jitter(500 * 2 ** (attempt - 1)), signal);
    }
  }

  throw lastError ?? new Error("Embeddings request failed");
}

/**
 * Embed an arbitrary list of texts. Batches by `EMBEDDING_BATCH_SIZE`,
 * retries 429/5xx with exponential backoff, returns embeddings in the
 * same order as the input. Empty inputs are passed through as `null` so
 * callers can preserve alignment with their source list without filtering.
 */
export async function embedTexts(
  texts: ReadonlyArray<string>,
  options: EmbedTextsOptions,
): Promise<Array<number[] | null>> {
  const fetchImpl = options.fetchImpl ?? fetch;
  const result: Array<number[] | null> = new Array(texts.length).fill(null);
  const indexed = texts
    .map((text, originalIndex) => ({ text: (text ?? "").trim(), originalIndex }))
